"""
请求模型
"""
from pydantic import BaseModel, Field


class ProcessRequest(BaseModel):
    """文档处理请求"""

    filedata: str = Field(..., description="Base64编码的文件内容")
    filename: str = Field(..., description="文件名（包含后缀）")

    class Config:
        json_schema_extra = {
            "example": {
                "filedata": "",
                "filename": "example.pdf",
            }
        }
